const canvas = document.createElement('canvas');
const ctx = canvas.getContext('2d');

document.body.style.margin = '0';
document.body.style.overflow = 'hidden';
document.body.style.background = '#111';
document.body.appendChild(canvas);

function resize() {
  canvas.width = innerWidth;
  canvas.height = innerHeight;
}
addEventListener('resize', resize);
resize();

const keys = {};
addEventListener('keydown', e => {
  keys[e.key.toLowerCase()] = true;
});
addEventListener('keyup', e => {
  keys[e.key.toLowerCase()] = false;
});

const track = {
  x: 80,
  y: 80,
  w: 1200,
  h: 700,
  road: 220
};

const player = {
  x: track.x + track.w / 2,
  y: track.y + track.h - 120,
  angle: -Math.PI / 2,
  speed: 0,
  maxSpeed: 12,
  accel: 0.22,
  brake: 0.35,
  friction: 0.04,
  turnRate: 0.045,
  lapStart: performance.now(),
  distance: 0
};

let lastFrame = performance.now();
let gameTime = 0;

function clamp(v, min, max) {
  return Math.max(min, Math.min(max, v));
}

function movePlayer(deltaMs) {
  const dt = deltaMs / 16.6667;
  const now = performance.now();

  if (keys['arrowup'] || keys['w']) player.speed += player.accel * dt;
  if (keys['arrowdown'] || keys['s']) player.speed -= player.brake * dt;

  if (!(keys['arrowup'] || keys['w']) && !(keys['arrowdown'] || keys['s'])) {
    if (player.speed > 0) player.speed = Math.max(0, player.speed - player.friction * dt);
    if (player.speed < 0) player.speed = Math.min(0, player.speed + player.friction * dt);
  }

  player.speed = clamp(player.speed, -player.maxSpeed / 2, player.maxSpeed);

  if (keys['arrowleft'] || keys['a']) player.angle -= player.turnRate * dt * (0.3 + Math.abs(player.speed) / player.maxSpeed);
  if (keys['arrowright'] || keys['d']) player.angle += player.turnRate * dt * (0.3 + Math.abs(player.speed) / player.maxSpeed);

  const dx = Math.cos(player.angle) * player.speed * dt * 4;
  const dy = Math.sin(player.angle) * player.speed * dt * 4;

  player.x += dx;
  player.y += dy;

  player.distance += Math.hypot(dx, dy);

  const left = track.x + track.road / 2;
  const right = track.x + track.w - track.road / 2;
  const top = track.y + track.road / 2;
  const bottom = track.y + track.h - track.road / 2;

  if (player.x < left) { player.x = left; player.speed *= 0.7; }
  if (player.x > right) { player.x = right; player.speed *= 0.7; }
  if (player.y < top) { player.y = top; player.speed *= 0.7; }
  if (player.y > bottom) { player.y = bottom; player.speed *= 0.7; }

  if (player.y < track.y + 100 && Math.abs(player.x - (track.x + track.w / 2)) < 80 && player.speed > 0) {
    if (now - player.lapStart > 1000) {
      player.lapStart = now;
      player.distance = 0;
    }
  }
}

function drawTrack() {
  ctx.fillStyle = '#1c7c2f';
  ctx.fillRect(0, 0, canvas.width, canvas.height);

  ctx.fillStyle = '#555';
  ctx.fillRect(track.x, track.y, track.w, track.h);

  ctx.strokeStyle = '#fff';
  ctx.lineWidth = 6;
  ctx.setLineDash([22, 16]);
  ctx.strokeRect(track.x + track.road / 2, track.y + track.road / 2, track.w - track.road, track.h - track.road);
  ctx.setLineDash([]);

  ctx.fillStyle = '#333';
  ctx.fillRect(track.x + track.road / 2, track.y + track.road / 2, track.w - track.road, track.h - track.road);

  ctx.fillStyle = '#ffd700';
  ctx.fillRect(track.x + track.w / 2 - 60, track.y + 16, 120, 18);
  ctx.fillStyle = '#fff';
  ctx.fillRect(track.x + track.w / 2 - 2, track.y + 16, 4, 50);
}

function drawPlayer() {
  ctx.save();
  ctx.translate(player.x, player.y);
  ctx.rotate(player.angle);

  ctx.fillStyle = '#e74c3c';
  ctx.fillRect(-18, -10, 36, 20);
  ctx.fillStyle = '#222';
  ctx.fillRect(-10, -14, 20, 8);
  ctx.fillStyle = '#111';
  ctx.fillRect(-16, -12, 6, 5);
  ctx.fillRect(10, -12, 6, 5);
  ctx.fillRect(-16, 7, 6, 5);
  ctx.fillRect(10, 7, 6, 5);

  ctx.restore();
}

function drawHUD() {
  ctx.fillStyle = 'rgba(0,0,0,0.55)';
  ctx.fillRect(18, 18, 260, 96);
  ctx.fillStyle = '#fff';
  ctx.font = '18px sans-serif';
  ctx.fillText('Speed: ' + player.speed.toFixed(2), 30, 46);
  ctx.fillText('Distance: ' + player.distance.toFixed(1), 30, 72);
  ctx.fillText('Time: ' + ((performance.now() - player.lapStart) / 1000).toFixed(2) + 's', 30, 98);
}

function loop() {
  const now = performance.now();
  const delta = now - lastFrame;
  lastFrame = now;
  gameTime += delta;

  movePlayer(delta);

  ctx.clearRect(0, 0, canvas.width, canvas.height);
  drawTrack();
  drawPlayer();
  drawHUD();

  requestAnimationFrame(() => {});
}

setInterval(() => {
  const now = performance.now();
  const delta = now - lastFrame;
  lastFrame = now;
  gameTime += delta;
  movePlayer(delta);
  ctx.clearRect(0, 0, canvas.width, canvas.height);
  drawTrack();
  drawPlayer();
  drawHUD();
}, 16);